+/// Cached precomputed parameters for NumPy-compatible binomial sampling.
+/// Avoids recomputation when the same `(n, p)` pair is used repeatedly.
+/// Matches `binomial_t` in NumPy's distributions.h.
+#[derive(Debug, Clone)]
+struct BinomialCache {
+    has_binomial: bool,
+    psave: f64,
+    nsave: i64,
+    r: f64,
+    q: f64,
+    fm: f64,
+    m: i64,
+    p1: f64,
+    xm: f64,
+    xl: f64,
+    xr: f64,
+    c: f64,
+    laml: f64,
+    lamr: f64,
+    p2: f64,
+    p3: f64,
+    p4: f64,
+}
